text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트가 통과하는 경우 금요일 15:00 KST를 공개 릴리스 목표 시점으로 한다.",
        "conditions": [
          "스모크 테스트 통과"
        ],
        "source_certainty": "confirmed"
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다.",
        "source_certainty": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "topic": "smoke-theme-pack.mjs 처리 방식",
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경한다.",
        "result": "rejected",
        "source_certainty": "confirmed"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 스트레치 목표",
        "note": "최종 공개 릴리스 결정이 아니며, 스모크 테스트 선행 조건을 대체하지 않는다.",
        "source_certainty": "confirmed"
      }
    ],
    "non_decisions": [
      {
        "topic": "README 설치 단계 검토",
        "note": "목요일까지 가능하면 검토하자는 의견이 있었으나 담당자는 지정되지 않았다.",
        "source_certainty": "partial"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 인해 릴리스가 지연될 수 있다.",
        "source_certainty": "confirmed"
      },
      {
        "risk": "README 설치 단계가 오래된 상태라면 릴리스 노트가 사용자에게 오해를 줄 수 있다.",
        "source_certainty": "confirmed"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "status": "open",
        "source_certainty": "confirmed"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?",
        "status": "open",
        "source_certainty": "confirmed"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "open",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "open",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "blocked_on_smoke_result",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README 설치 단계를 목요일까지 가능하면 검토한다.",
      "due": "목요일 가능 시",
      "status": "unassigned",
      "source_certainty": "partial"
    }
  ],
  "followup_note": {
    "check_next": [
      "금요일 10:00 KST의 스모크 테스트 결과 통과 여부를 먼저 확인한다.",
      "스모크 결과 공유 후 tarball 경로 검증 결과를 확인한다.",
      "금요일 12:00 KST까지 failure triage note가 action_items.md에 기록되었는지 확인한다.",
      "최종 릴리스 승인 권한자 확인이 필요하다.",
      "릴리스 노트에 수요일 내부 스트레치 목표를 언급할지 여부는 별도 결정이 필요하다.",
      "README 설치 단계 검토는 필요하지만 현재 담당자가 지정되지 않았음을 유지한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "지정되지 않은 담당자",
      "명시되지 않은 마감시한"
    ]
  },
  "non_invention_rules": [
    "인라인 픽스처에 없는 고객 정보를 추가하지 않는다.",
    "예산, 보안, 장애, 법무 관련 사실을 새로 만들지 않는다.",
    "담당자가 지정되지 않은 항목에 임의로 owner를 부여하지 않는다.",
    "정확한 기한이 없는 항목에 임의의 deadline을 부여하지 않는다.",
    "수요일 일정은 확정 릴리스가 아니라 내부 스트레치 목표로만 기록한다.",
    "거절된 제안과 확정된 결정은 분리해서 기록한다.",
    "열린 질문은 결정된 사항처럼 표현하지 않는다."
  ]
}
